1439: void EventListenerManager::HandleEventInternal(nsPresContext* aPresContext,
1440:                                                WidgetEvent* aEvent,
1441:                                                Event** aDOMEvent,
1442:                                                EventTarget* aCurrentTarget,
1443:                                                nsEventStatus* aEventStatus,
1444:                                                bool aItemInShadowTree) {
1445:   MOZ_ASSERT_IF(aEvent->mMessage != eUnidentifiedEvent, mIsMainThreadELM);
1446: 
1447:   // Set the value of the internal PreventDefault flag properly based on
1448:   // aEventStatus
1449:   if (!aEvent->DefaultPrevented() &&
1450:       *aEventStatus == nsEventStatus_eConsumeNoDefault) {
1451:     // Assume that if only aEventStatus claims that the event has already been
1452:     // consumed, the consumer is default event handler.
1453:     aEvent->PreventDefault();
1454:   }
1455: 
1456:   if (aEvent->mFlags.mImmediatePropagationStopped) {
1457:     return;
1458:   }
1459: 
1460:   Maybe<AutoHandlingUserInputStatePusher> userInputStatePusher;
1461:   Maybe<AutoPopupStatePusher> popupStatePusher;
1462:   if (mIsMainThreadELM) {
1463:     userInputStatePusher.emplace(UserActivation::IsUserInteractionEvent(aEvent),
1464:                                  aEvent);
1465:     popupStatePusher.emplace(
1466:         PopupBlocker::GetEventPopupControlState(aEvent, *aDOMEvent));
1467:   }
1468: 
1469:   RefPtr<nsAtom> typeAtom = nsContentUtils::GetEventType(aEvent);
1470:   if (!typeAtom) {
1471:     // Some messages don't have a corresponding type atom, e.g.
1472:     // eMouseEnterIntoWidget. These events can't have a listener, so we
1473:     // can stop here.
1474:     return;
1475:   }
1476: 
1477:   EventMessage eventMessage = aEvent->mMessage;
1478:   bool hasAnyListenerForEventType = false;
1479: 
1480:   // First, notify any "all events" listeners.
1481:   if (RefPtr<ListenerArray> listenersForAllEvents =
1482:           mListenerMap.GetListenersForAllEvents()) {
1483:     HandleEventWithListenerArray(listenersForAllEvents, typeAtom, eventMessage,
1484:                                  aPresContext, aEvent, aDOMEvent,
1485:                                  aCurrentTarget, aItemInShadowTree);
1486:     hasAnyListenerForEventType = true;
1487:   }
1488: 
1489:   // Now look for listeners for typeAtom, and call them if we have any.
1490:   bool hasAnyListenerMatchingGroup = false;
1491:   if (RefPtr<ListenerArray> listeners =
1492:           mListenerMap.GetListenersForType(typeAtom)) {
1493:     hasAnyListenerMatchingGroup = HandleEventWithListenerArray(
1494:         listeners, typeAtom, eventMessage, aPresContext, aEvent, aDOMEvent,
1495:         aCurrentTarget, aItemInShadowTree);
1496:     hasAnyListenerForEventType = true;
1497:   }
1498: 
1499:   if (!hasAnyListenerMatchingGroup && aEvent->IsTrusted()) {
1500:     // If we didn't find any matching listeners, and our event has a legacy
1501:     // version, check the listeners for the legacy version.
1502:     EventMessage legacyEventMessage = GetLegacyEventMessage(eventMessage);
1503:     if (legacyEventMessage != eventMessage) {
1504:       MOZ_ASSERT(
1505:           GetLegacyEventMessage(legacyEventMessage) == legacyEventMessage,
1506:           "Legacy event messages should not themselves have legacy versions");
1507:       RefPtr<nsAtom> legacyTypeAtom =
1508:           nsContentUtils::GetEventTypeFromMessage(legacyEventMessage);
1509:       if (RefPtr<ListenerArray> legacyListeners =
1510:               mListenerMap.GetListenersForType(legacyTypeAtom)) {
1511:         HandleEventWithListenerArray(
1512:             legacyListeners, legacyTypeAtom, legacyEventMessage, aPresContext,
1513:             aEvent, aDOMEvent, aCurrentTarget, aItemInShadowTree);
1514:         hasAnyListenerForEventType = true;
1515:       }
1516:     }
1517:   }
1518: 
1519:   aEvent->mCurrentTarget = nullptr;
1520: 
1521:   if (mIsMainThreadELM && !hasAnyListenerForEventType) {
1522:     if (aEvent->mMessage != eUnidentifiedEvent) {
1523:       mNoListenerForEvents[2] = mNoListenerForEvents[1];
1524:       mNoListenerForEvents[1] = mNoListenerForEvents[0];
1525:       mNoListenerForEvents[0] = aEvent->mMessage;
1526:     } else {
1527:       mNoListenerForEventAtom = aEvent->mSpecifiedEventType;
1528:     }
1529:   }
1530: 
1531:   if (aEvent->DefaultPrevented()) {
1532:     *aEventStatus = nsEventStatus_eConsumeNoDefault;
1533:   }
1534: }
