1297: /* static */ EventMessage EventListenerManager::GetLegacyEventMessage(
1298:     EventMessage aEventMessage) {
1299:   // webkit-prefixed legacy events:
1300:   if (aEventMessage == eTransitionEnd) {
1301:     return eWebkitTransitionEnd;
1302:   }
1303:   if (aEventMessage == eAnimationStart) {
1304:     return eWebkitAnimationStart;
1305:   }
1306:   if (aEventMessage == eAnimationEnd) {
1307:     return eWebkitAnimationEnd;
1308:   }
1309:   if (aEventMessage == eAnimationIteration) {
1310:     return eWebkitAnimationIteration;
1311:   }
1312: 
1313:   switch (aEventMessage) {
1314:     case eFullscreenChange:
1315:       return eMozFullscreenChange;
1316:     case eFullscreenError:
